import{_ as e,o,c as a,ag as r}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Porta Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"porta/index.md","filePath":"porta/index.md"}'),n={name:"porta/index.md"};function i(s,t,l,h,c,d){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="porta-quick-start" tabindex="-1">Porta Quick Start <a class="header-anchor" href="#porta-quick-start" aria-label="Permalink to &quot;Porta Quick Start&quot;">​</a></h1><p>Welcome to your Porta. This page walks you through the three things you need to do the first time: connect to the patcher, make sure the firmware is current, and upload your first patch.</p><p>Everything happens in your web browser over USB-C -- there is nothing to install.</p><div class="info custom-block"><p class="custom-block-title">You need</p><ul><li>A <strong>data-capable USB-C cable</strong> (charge-only cables will not work)</li><li><strong>Chrome</strong>, <strong>Edge</strong>, or <strong>Opera</strong> on a desktop or laptop (Web Serial is not available in Firefox, Safari, or mobile browsers)</li></ul></div><div class="tip custom-block"><p class="custom-block-title">First, charge the battery</p><p>Plug your Porta into USB-C and let the battery charge before first use -- this takes roughly <strong>2-3 hours</strong>. You can carry on with the steps below while it charges.</p></div><h2 id="_1-connect-to-the-patcher" tabindex="-1">1. Connect to the patcher <a class="header-anchor" href="#_1-connect-to-the-patcher" aria-label="Permalink to &quot;1. Connect to the patcher&quot;">​</a></h2><ol><li>Plug the Porta into your computer with the USB-C cable and switch it on.</li><li>Open the patcher at <strong><a href="https://soniphorm.com/patcher" target="_blank" rel="noreferrer">soniphorm.com/patcher</a></strong>.</li><li>Click the <strong>Connect</strong> button in the toolbar (the plug icon).</li><li>A browser dialog lists the available serial ports -- choose the entry for your Porta and click <strong>Connect</strong>.</li><li>The toolbar shows a connected state once the link is open.</li></ol><div class="tip custom-block"><p class="custom-block-title">Confirm it worked</p><p>Open the <strong>Serial Console</strong> from the toolbar, type <code>STATUS</code>, and press Enter. You should see the firmware version, CPU usage, and current patch.</p></div><h2 id="_2-check-the-firmware-is-up-to-date" tabindex="-1">2. Check the firmware is up to date <a class="header-anchor" href="#_2-check-the-firmware-is-up-to-date" aria-label="Permalink to &quot;2. Check the firmware is up to date&quot;">​</a></h2><ol><li>With the Porta connected, click the <strong>firmware update</strong> button in the toolbar (the chip icon).</li><li>The panel shows your <strong>current version</strong> alongside the <strong>latest available</strong> version: <ul><li><strong>&quot;Firmware is up to date&quot;</strong> -- nothing to do, skip to step 3.</li><li><strong>&quot;Update available&quot;</strong> -- continue below.</li></ul></li><li>Click <strong>Update Firmware</strong>. The Porta reboots itself into update mode automatically -- there are no buttons to hold.</li><li>When the browser asks, select the Porta in the port chooser and let it flash. Progress runs to 100%, then the panel confirms the update.</li></ol><h3 id="if-the-update-can-t-connect" tabindex="-1">If the update can&#39;t connect <a class="header-anchor" href="#if-the-update-can-t-connect" aria-label="Permalink to &quot;If the update can&#39;t connect&quot;">​</a></h3><p>On Windows the Porta sometimes needs a nudge to re-appear as an update device. If the patcher reports it can&#39;t connect:</p><ol><li><strong>Unplug and replug the USB-C cable.</strong></li><li><strong>Power-cycle the Porta</strong> -- switch it off, wait a couple of seconds, switch it back on.</li><li>Click <strong>Flash</strong> again and reselect the port.</li></ol><p>This is a known ESP32-S3 quirk on Windows and is harmless -- the Porta is never in a bad state, it just needs to re-enumerate.</p><h2 id="_3-upload-your-first-patch" tabindex="-1">3. Upload your first patch <a class="header-anchor" href="#_3-upload-your-first-patch" aria-label="Permalink to &quot;3. Upload your first patch&quot;">​</a></h2><ol><li>Back on the main patcher canvas, open the menu and <strong>load an example patch</strong>, or build your own.</li><li>Click the <strong>Upload</strong> button in the toolbar (the arrow icon).</li><li>The patch transfers as JSON over USB -- you&#39;ll hear the result immediately.</li><li>The serial console shows the upload progress and a confirmation when it finishes.</li></ol><p>The Porta keeps running the last patch you uploaded even after you unplug it -- the patch lives on the device, so you can take it anywhere.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Solution</th></tr></thead><tbody><tr><td>No ports listed when connecting</td><td>Check the USB-C cable is data-capable. Try a different port. Close Arduino IDE / serial terminals.</td></tr><tr><td>Update can&#39;t connect</td><td>Unplug and replug USB-C, power-cycle the Porta, then retry Flash.</td></tr><tr><td>&quot;Failed to open serial port&quot;</td><td>Another app is using the port. Close it and retry.</td></tr><tr><td>Connection drops</td><td>Use a shorter cable and avoid USB hubs.</td></tr></tbody></table><p>Need more help? Join the <a href="https://discord.gg/yAFWg4eQXQ" target="_blank" rel="noreferrer">Soniphorm Discord</a>.</p>',20)])])}const g=e(n,[["render",i]]);export{u as __pageData,g as default};
